//功能：画圆函数

//返回值：void
function DrawCircles() {
    let p = [center_x, center_y];
    var a = 2 * Math.PI * time / path.length;
    for (var i = 0; i < Cn.length; i++) {
        context.beginPath();
        var r = Math.hypot(Cn[i][0], Cn[i][1]);
        context.arc(p[0], p[1], r, 0, 2 * Math.PI);
        context.lineWidth = 1.0;
        context.strokeStyle = "rgba(255,128,32,0.7)";
        if (i > 0) {
            context.stroke();   //第一个圆不画
        }
        p = add(p, mul(Cn[i], exp(a * K[i])));
    }
}

//功能：绘制路径函数

//返回值：void
function DrawPath() {
    let p = [center_x, center_y];
    var a = 2 * Math.PI * time / path.length;
    for (var i = 0; i < Cn.length; i++) {
        p = add(p, mul(Cn[i], exp(a * K[i])));
    }
    var x = p[0];
    var y = p[1];
    valuePointer++;
    values_x[valuePointer & pointCount] = x;
    values_y[valuePointer & pointCount] = y;
    context.beginPath();
    context.strokeStyle = "rgba(0,255,0,1)";
    context.moveTo(x, y);
    for (var i = 1; i <= pointCount; ++i) {
        context.lineTo(values_x[(valuePointer - i) & pointCount], values_y[(valuePointer - i) & pointCount]);
    }
    context.stroke();
}

//绘制连接圆心函数
//返回值：void
function DrawLines() {
    context.beginPath();
    let p = [center_x, center_y];
    var a = 2 * Math.PI * time / path.length;
    for (var i = 0; i < Cn.length; i++) {
        if (i == 1) {
            context.moveTo(p[0], p[1]);     //第一个线不画
        }
        p = add(p, mul(Cn[i], exp(a * K[i])))
        context.lineTo(p[0], p[1]);
    }
    context.lineWidth = 1;
    context.strokeStyle = "rgba(255,255,255,0.6)";
    context.stroke();
}

function DrawText() {
    //写字
    context.fillStyle = 'rgba(255,255,0,0.6)';
    context.font = fontSize + 'px Microsoft Yahei';
    context.textAlign = 'left';
    var pos_x = center_x + text_offset_x;
    var pos_y = center_y + text_offset_y;
    //pos_x += 50;
    //pos_y -= 50;
}
var temp_count = 0;
function drawSigma() {
    context.beginPath();
    context.strokeStyle = "rgba(0,255,0,1)";
    context.moveTo(path[0][0], path[0][1]);
    for (var i = 0; i <= temp_count; i++) {
        context.lineTo(path[i][0], path[i][1]);
    }
    context.stroke();
}

function getCenter() {
    var a = 0;
    var b = 0;
    var arr = [];
    for (var i = 0; i < path.length; i++) {
        a += path[i][0];
        b += path[i][1];
    }
    a = a / path.length;
    b = b / path.length;
    return [a, b];
}

//var zb = [Math.cos(K[j] * i / N * 2 * -Math.PI), Math.sin(K[j] * i / N * 2 * -Math.PI)];    //e^nt

//函数功能：穷举法计算复向量系数c_n
//返回值：[]
function getCn() {
    var z = [0, 0];
    var N = path.length;        //路径坐标数组
    for (var j = 0; j < K.length; j++) {
        for (var i = 0; i < N; i++) {
            var za = [path[i][0], path[i][1]];          //f(t)
            var zb = exp(K[j] * i * 2 * -Math.PI / N);  //调用指数转复数函数
            z = add(z, mul(za, zb));                    //调用相乘函数
        }
        z[0] = z[0] / N;
        z[1] = z[1] / N;
        Cn[j] = [z[0], z[1]];
    }
}

function sleep(numberMillis) {
    var now = new Date();
    var exitTime = now.getTime() + numberMillis;
    while (true) {
        now = new Date();
        if (now.getTime() > exitTime) {
            return;
        }
    }
}

//功能：复数运算法则
//返回类型：[]


//功能：指数转化为复数
function exp(theta) {
    return [Math.cos(theta), Math.sin(theta)];
}
//功能：两个复数相乘
function mul(za, zb) {
    return [za[0] * zb[0] - za[1] * zb[1], za[0] * zb[1] + za[1] * zb[0]];
}
//功能：两个复数相加
function add(za, zb) {
    return [za[0] + zb[0], za[1] + zb[1]];
}

//功能：储存下标值

//返回值：[]
var circleCount = 500; //圆的数量
var K = [];
for (var i = 0; i < circleCount; i++) {
    K[i] = (1 + i >> 1) * (i & 1 ? -1 : 1);
}

var Cn = [];
for (var i = 0; i < K.length; i++) {
    Cn[i] = [0, 0];
}

//计算出质心，后续用来存放大致屏幕位置
center_x = getCenter()[0];
center_y = getCenter()[1];

//加上大致的偏移量，放到中心
center_x = center_x + offset_x;
center_y = center_y + offset_y;

//获取Cnx系数
getCn();

//将第一个点作为相对零点坐标
for (var i = 0; i < path.length; i++) {
    path[i][0] = path[i][0] - center_x;
    path[i][1] = path[i][1] - center_y;
}

//循环刷新函数
//
(function frame() {
    context.clearRect(0, 0, canvas.width, canvas.height);
    context.fillStyle = "#000000";
    context.fillRect(0, 0, canvas.width, canvas.height);

    DrawCircles();
    DrawPath();
    DrawLines();
    DrawText();
    time = time + 2;
    window.requestAnimationFrame(frame);
})();
